class Solution:
    def numberOfSubmatrices(self, grid) -> int:
        R, C = len(grid), len(grid[0])
        count = 0
        for r in range(R):
            for c in range(C):
                cx = cy = 0
                for i in range(r + 1):
                    for j in range(c + 1):
                        if grid[i][j] == 'X': cx += 1
                        elif grid[i][j] == 'Y': cy += 1
                if cx > 0 and cx == cy:
                    count += 1
        return count

