var numberOfSubmatrices = function(grid) {
    const R = grid.length, C = grid[0].length;
    const px = Array.from({length: R+1}, () => new Array(C+1).fill(0));
    const py = Array.from({length: R+1}, () => new Array(C+1).fill(0));
    let count = 0;
    for (let r = 0; r < R; r++) {
        for (let c = 0; c < C; c++) {
            const dx = grid[r][c] === 'X' ? 1 : 0;
            const dy = grid[r][c] === 'Y' ? 1 : 0;
            px[r+1][c+1] = px[r][c+1] + px[r+1][c] - px[r][c] + dx;
            py[r+1][c+1] = py[r][c+1] + py[r+1][c] - py[r][c] + dy;
            const cx = px[r+1][c+1], cy = py[r+1][c+1];
            if (cx > 0 && cx === cy) count++;
        }
    }
    return count;
};
